/**
 * @jest-environment @edge-runtime/jest-environment
 */

import {
  geo,
  geoFromHeaders,
  getCountryName,
  isInRegion,
  haversineDistance,
} from 'next/dist/server/web/spec-extension/geo'

// Fixture coordinates
const LONDON = { lat: 51.5074, lon: -0.1278 }
const PARIS = { lat: 48.8566, lon: 2.3522 }
const NEW_YORK = { lat: 40.7128, lon: -74.006 }
const LOS_ANGELES = { lat: 34.0522, lon: -118.2437 }
const SYDNEY = { lat: -33.8688, lon: 151.2093 }
const AUCKLAND = { lat: -36.8485, lon: 174.7633 }

// ---------------------------------------------------------------------------
// geo() / geoFromHeaders()
// ---------------------------------------------------------------------------

describe('geoFromHeaders', () => {
  it('extracts all six Vercel headers when present', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })
    expect(geoFromHeaders(headers)).toEqual({
      country: 'US',
      city: 'San Francisco',
      region: 'CA',
      latitude: '37.7749',
      longitude: '-122.4194',
      timezone: 'America/Los_Angeles',
    })
  })

  it('decodes percent-encoded city name', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San%20Francisco',
    })
    expect(geoFromHeaders(headers).city).toBe('San Francisco')
  })

  it('falls back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = new Headers({ 'cf-ipcountry': 'DE' })
    expect(geoFromHeaders(headers).country).toBe('DE')
  })

  it('falls back to cf-ipcity when x-vercel-ip-city is absent', () => {
    const headers = new Headers({ 'cf-ipcity': 'Berlin' })
    expect(geoFromHeaders(headers).city).toBe('Berlin')
  })

  it('returns empty object when no geo headers are present', () => {
    const headers = new Headers({ 'content-type': 'application/json' })
    expect(geoFromHeaders(headers)).toEqual({})
  })

  it('geo() and geoFromHeaders() return identical results', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'JP',
      'x-vercel-ip-city': 'Tokyo',
    })
    expect(geo({ headers })).toEqual(geoFromHeaders(headers))
  })

  it('Vercel header takes precedence over Cloudflare fallback', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'US',
      'cf-ipcountry': 'DE',
    })
    expect(geoFromHeaders(headers).country).toBe('US')
  })

  it('does not throw on malformed percent-encoded city', () => {
    const headers = new Headers({ 'x-vercel-ip-city': '%E0%A4%A' })
    expect(() => geoFromHeaders(headers)).not.toThrow()
    // Falls back to raw value
    expect(geoFromHeaders(headers).city).toBe('%E0%A4%A')
  })
})

// ---------------------------------------------------------------------------
// getCountryName()
// ---------------------------------------------------------------------------

describe('getCountryName', () => {
  it('returns "United States" for "US"', () => {
    expect(getCountryName('US')).toBe('United States')
  })

  it('is case-insensitive (lowercase input)', () => {
    expect(getCountryName('us')).toBe('United States')
  })

  it('returns "United Kingdom" for "GB"', () => {
    expect(getCountryName('GB')).toBe('United Kingdom')
  })

  it('returns "Germany" for "DE"', () => {
    expect(getCountryName('DE')).toBe('Germany')
  })

  it('returns "Japan" for "JP"', () => {
    expect(getCountryName('JP')).toBe('Japan')
  })

  it('returns undefined for unknown code "XX"', () => {
    expect(getCountryName('XX')).toBeUndefined()
  })

  it('returns undefined for empty string', () => {
    expect(getCountryName('')).toBeUndefined()
  })
})

// ---------------------------------------------------------------------------
// isInRegion()
// ---------------------------------------------------------------------------

describe('isInRegion', () => {
  it('"DE" is in EU', () => {
    expect(isInRegion('DE', 'EU')).toBe(true)
  })

  it('"DE" is in EEA', () => {
    expect(isInRegion('DE', 'EEA')).toBe(true)
  })

  it('"NO" is in EEA but not EU', () => {
    expect(isInRegion('NO', 'EEA')).toBe(true)
    expect(isInRegion('NO', 'EU')).toBe(false)
  })

  it('"US" is not in EU but is in NA', () => {
    expect(isInRegion('US', 'EU')).toBe(false)
    expect(isInRegion('US', 'NA')).toBe(true)
  })

  it('"BR" is in LATAM', () => {
    expect(isInRegion('BR', 'LATAM')).toBe(true)
  })

  it('"MX" is in both NA and LATAM', () => {
    expect(isInRegion('MX', 'NA')).toBe(true)
    expect(isInRegion('MX', 'LATAM')).toBe(true)
  })

  it('"JP" and "AU" are in APAC', () => {
    expect(isInRegion('JP', 'APAC')).toBe(true)
    expect(isInRegion('AU', 'APAC')).toBe(true)
  })

  it('"DE" is not in APAC', () => {
    expect(isInRegion('DE', 'APAC')).toBe(false)
  })

  it('accepts an explicit string array', () => {
    expect(isInRegion('US', ['US', 'CA'])).toBe(true)
    expect(isInRegion('DE', ['US', 'CA'])).toBe(false)
  })

  it('is case-insensitive for named region', () => {
    expect(isInRegion('us', 'NA')).toBe(true)
  })

  it('is case-insensitive for explicit array', () => {
    expect(isInRegion('US', ['us', 'ca'])).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// haversineDistance()
// ---------------------------------------------------------------------------

describe('haversineDistance', () => {
  it('returns 0 for the same point', () => {
    expect(haversineDistance(LONDON.lat, LONDON.lon, LONDON.lat, LONDON.lon)).toBe(0)
  })

  it('calculates London↔Paris ≈ 340 km', () => {
    const d = haversineDistance(LONDON.lat, LONDON.lon, PARIS.lat, PARIS.lon)
    expect(d).toBeGreaterThan(320)
    expect(d).toBeLessThan(360)
  })

  it('calculates NYC↔LA ≈ 3940 km', () => {
    const d = haversineDistance(
      NEW_YORK.lat,
      NEW_YORK.lon,
      LOS_ANGELES.lat,
      LOS_ANGELES.lon
    )
    expect(d).toBeGreaterThan(3900)
    expect(d).toBeLessThan(3980)
  })

  it('defaults to km', () => {
    const d1 = haversineDistance(LONDON.lat, LONDON.lon, PARIS.lat, PARIS.lon)
    const d2 = haversineDistance(
      LONDON.lat,
      LONDON.lon,
      PARIS.lat,
      PARIS.lon,
      'km'
    )
    expect(d1).toBe(d2)
  })

  it('calculates London↔Paris in miles ≈ 211 mi', () => {
    const d = haversineDistance(
      LONDON.lat,
      LONDON.lon,
      PARIS.lat,
      PARIS.lon,
      'mi'
    )
    expect(d).toBeGreaterThan(195)
    expect(d).toBeLessThan(225)
  })

  it('calculates NYC↔LA in miles ≈ 2451 mi', () => {
    const d = haversineDistance(
      NEW_YORK.lat,
      NEW_YORK.lon,
      LOS_ANGELES.lat,
      LOS_ANGELES.lon,
      'mi'
    )
    expect(d).toBeGreaterThan(2420)
    expect(d).toBeLessThan(2480)
  })

  it('is symmetric: distance(A,B) === distance(B,A)', () => {
    const d1 = haversineDistance(LONDON.lat, LONDON.lon, PARIS.lat, PARIS.lon)
    const d2 = haversineDistance(PARIS.lat, PARIS.lon, LONDON.lat, LONDON.lon)
    expect(d1).toBe(d2)
  })

  it('handles southern hemisphere (Sydney↔Auckland ≈ 2155 km)', () => {
    const d = haversineDistance(
      SYDNEY.lat,
      SYDNEY.lon,
      AUCKLAND.lat,
      AUCKLAND.lon
    )
    expect(d).toBeGreaterThan(2100)
    expect(d).toBeLessThan(2220)
  })

  it('returns a finite number for antipodal points', () => {
    const d = haversineDistance(0, 0, 0, 180)
    expect(Number.isFinite(d)).toBe(true)
    expect(Number.isNaN(d)).toBe(false)
  })
})

